private void GenTransitiveValidation(ValidatedMember vm, ref Dictionary<string, StaticFieldInfo> staticValidatorsDict)
        {
            string callSequence;
            if (vm.TransValidateTypeIsSynthetic)
            {
                callSequence = vm.TransValidatorType!;
            }
            else
            {
                var staticValidatorInstance = GetOrAddStaticValidator(ref staticValidatorsDict, vm.TransValidatorType!);

                callSequence = $"{_staticValidatorHolderClassFQN}.{staticValidatorInstance.FieldName}";
            }

            var valueAccess = (vm.IsNullable && vm.IsValueType) ? ".Value" : string.Empty;

            var baseName = $"string.IsNullOrEmpty(name) ? \"{vm.Name}\" : $\"{{name}}.{vm.Name}\"";

            if (vm.IsNullable)
            {
                OutLn($"if (options.{vm.Name} is not null)");
                OutOpenBrace();
                OutLn($"(builder ??= new()).AddResult({callSequence}.Validate({baseName}, options.{vm.Name}{valueAccess}));");
                OutCloseBrace();
            }
            else
            {
                OutLn($"(builder ??= new()).AddResult({callSequence}.Validate({baseName}, options.{vm.Name}{valueAccess}));");
            }
        }

private async Task<string> ReadLineAsync(CancellationToken cancellationToken)
        {
            var lineBuilder = new StringBuilder();
            var buffer = new byte[1];
            var previousWasCr = false;

            while (true)
            {
                var bytesRead = await _stream.ReadAsync(buffer, 0, 1, cancellationToken);
                if (bytesRead == 0)
                {
                    return lineBuilder.Length > 0 ? lineBuilder.ToString() : null;
                }

                var c = (char)buffer[0];

                if (c == '\n' && previousWasCr)
                {
                    if (lineBuilder.Length > 0 && lineBuilder[lineBuilder.Length - 1] == '\r')
                    {
                        lineBuilder.Length--;
                    }
                    return lineBuilder.ToString();
                }

                previousWasCr = c == '\r';
                lineBuilder.Append(c);

                if (lineBuilder.Length > _maxHeaderLineLength)
                {
                    throw new InvalidDataException($"Header line exceeds maximum length of {_maxHeaderLineLength}");
                }
            }
        }

internal void OnJobCompleted()
        {
            Trace.Info("Job completed, sending terminated event");

            int exitCode;
            lock (_stateLock)
            {
                if (_state == DapSessionState.Terminated)
                {
                    Trace.Info("Session already terminated, skipping OnJobCompleted events");
                    return;
                }
                _state = DapSessionState.Terminated;
                exitCode = _jobContext?.Result == TaskResult.Succeeded ? 0 : 1;
            }

            SendEvent(new Event
            {
                EventType = "terminated",
                Body = new TerminatedEventBody()
            });

            SendEvent(new Event
            {
                EventType = "exited",
                Body = new ExitedEventBody
                {
                    ExitCode = exitCode
                }
            });
        }

public List<Scope> GetScopes(IExecutionContext context)
        {
            var scopes = new List<Scope>();

            if (context?.ExpressionValues == null)
            {
                return scopes;
            }

            for (int i = 0; i < _scopeNames.Length; i++)
            {
                var scopeName = _scopeNames[i];
                if (!context.ExpressionValues.TryGetValue(scopeName, out var value) || value == null)
                {
                    continue;
                }

                var scope = new Scope
                {
                    Name = scopeName,
                    VariablesReference = _scopeReferenceBase + i,
                    Expensive = false,
                    PresentationHint = scopeName == "secrets" ? "registers" : null
                };

                if (value is DictionaryContextData dict)
                {
                    scope.NamedVariables = dict.Count;
                }
                else if (value is CaseSensitiveDictionaryContextData csDict)
                {
                    scope.NamedVariables = csDict.Count;
                }

                scopes.Add(scope);
            }

            return scopes;
        }

public int? TryClaimPredictedStep(string matchKey, IStep step)
        {
            if (string.IsNullOrEmpty(matchKey) || step == null)
            {
                return null;
            }

            lock (_lock)
            {
                var existingLine = TryGetLineForStepNoLock(step);
                if (existingLine.HasValue)
                {
                    return existingLine;
                }

                foreach (var entry in _postEntries)
                {
                    if (!string.Equals(entry.MatchKey, matchKey, StringComparison.Ordinal))
                    {
                        continue;
                    }

                    if (entry.Step != null && !ReferenceEquals(entry.Step, step))
                    {
                        return null;
                    }

                    entry.Step = step;
                    Render();
                    return TryGetLineForStepNoLock(step);
                }

                return null;
            }
        }
